import{g as o,b as r,c as a,h as t}from"./chunks/framework.ebJuSMhv.js";const g=JSON.parse('{"title":"【教程】将你的Windows Phone升级到16212","description":"","frontmatter":{"date":"2022-07-04T00:00:00.000Z","title":"【教程】将你的Windows Phone升级到16212","tag":["Windows Phone","Beta"]},"headers":[],"relativePath":"posts/windows-phone-upgrade-16212/index.md","filePath":"posts/windows-phone-upgrade-16212/index.md"}'),p={name:"posts/windows-phone-upgrade-16212/index.md"};function l(n,e,i,s,d,c){return r(),a("div",null,[...e[0]||(e[0]=[t('<p>众所周知，2017年6月1日，微软推送了Windows 10 Mobile 16212。然而，此版本却是微软未经测试的内部版本，升级之后手机就会变砖。不久，微软就撤回了这次版本更新，w10m也永远停在了1709（实质上仍是1703）</p><p>本篇教程将介绍给Windows Phone推送16212.1000并正常启动的方法。</p><hr><p><strong>22.12.27更新</strong>:本教程只适用于存在10586系统的机器。 若你的手机初始版本高于10586，请参考原版教程。</p><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to “前言”">​</a></h2><p>众所周知，2017年6月1日，微软推送了Windows 10 Mobile 16212。然而，此版本却是微软未经测试的内部版本，升级之后手机就会变砖。不久，微软就撤回了这次版本更新，w10m也永远停在了1709（实质上仍是1703）</p><p>本篇教程将介绍给Windows Phone推送16212.1000并正常启动的方法。</p><p>效果演示：<a href="https://www.bilibili.com/video/BV1Yf4y1Z7dF" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1Yf4y1Z7dF</a></p><p>参考/原作：<a href="https://github.com/Empyreal96/W10M-16212-Guides/wiki/Update-using-Universal-Updater" target="_blank" rel="noreferrer">https://github.com/Empyreal96/W10M-16212-Guides/wiki/Update-using-Universal-Updater</a></p><blockquote><p><strong>警告！</strong> 这不是一个能够正常使用的Build。在升级前，请做好完整备份以及随时翻车的准备，本人不对此教程造成的手机变砖爆炸负责！</p><p>不建议给配置较低的手机推送此版本。</p></blockquote><h2 id="准备工具" tabindex="-1">准备工具 <a class="header-anchor" href="#准备工具" aria-label="Permalink to “准备工具”">​</a></h2><p>下载链接：<a href="https://pan.baidu.com/s/14bLtYY4FJjC4w8SftQrEVA?pwd=1919" target="_blank" rel="noreferrer">https://pan.baidu.com/s/14bLtYY4FJjC4w8SftQrEVA?pwd=1919</a> 提取码：1919</p><ul><li>Windows Phone Interna</li><li>iutool</li><li>Unversal Updater</li><li>Develop Menu Installer</li><li>RCSChecker</li><li>Sample Flight Enabler</li><li>Interop Tools 1.9.400</li></ul><h2 id="_1-1-刷回原版系统" tabindex="-1">1-1 刷回原版系统 <a class="header-anchor" href="#_1-1-刷回原版系统" aria-label="Permalink to “1-1 刷回原版系统”">​</a></h2><p>首先，将你的Windows Phone刷回官方版固件，同时确保版本号（WP8.1）≥14xxx。</p><blockquote><p><strong>注意</strong> 一定要刷回对应你手机RM号的原版固件，跨机型混刷可能会造成升级过程中出现无限重启等问题。</p></blockquote><h2 id="_1-2-更新至10586-107-1511" tabindex="-1">1-2 更新至10586.107（1511） <a class="header-anchor" href="#_1-2-更新至10586-107-1511" aria-label="Permalink to “1-2 更新至10586.107（1511）”">​</a></h2><blockquote><p>若你的手机初始固件即为此版本，可以跳过此步</p></blockquote><p>安装iutool后，打开Universal Updater，并等待软件读取手机信息。</p><p>若你的WP8.1系统符合要求，就会看到三个选项，其中一个是<code>10.0.10586.107</code>。输入此版本相对应的序号并回车，此程序就会自动开始下载相应的更新包。</p><p><img src="/posts/windows-phone-upgrade-16212/01.png" alt=""></p><blockquote><p>更新包大小约为1GB，由于存放更新包的网盘在外国，你可能需要一些特殊的方式来下载...</p><p><strong>建议</strong> 在下载完成后找到Unversal Updater文件夹，把那个名称乱七八糟的（对应你DEVICE INFORMATIONS中的Serial）文件夹复制一份存下来，如果你推送失败就可以在选可用更新时选3，找到复制下来的文件夹里边的Packages来离线推送（Unversal Updater会在新推送开始时删除原有文件）</p></blockquote><p>等到下载完成后，你就可以看到程序开始向手机传输数据并弹出一个窗口。待数据传输完成后，打开<strong>设置-手机更新</strong>可以看到有&quot;正在准备更新&quot;的进度条出现。此时，你可以拔掉连接手机的数据线（当然不拔也可以）</p><p><img src="/posts/windows-phone-upgrade-16212/02.png" alt=""></p><p>等进度条走完后，重启手机，就会进入更新安装阶段，等待一会就会完成。</p><h2 id="_2-1-更新至14393-1066-1607" tabindex="-1">2-1 更新至14393.1066（1607） <a class="header-anchor" href="#_2-1-更新至14393-1066-1607" aria-label="Permalink to “2-1 更新至14393.1066（1607）”">​</a></h2><p>进入系统后，将时间更改到<strong>2016年8月4日</strong>。</p><p>重新打开Unversal Updater，这次你可以看到可用的更新变成了<code>14393.1066</code>。</p><p><img src="/posts/windows-phone-upgrade-16212/03.png" alt=""></p><p>选择第一个选项，在开始下载前它会提示你<strong>是否需要移除RCS功能</strong>，选<strong>Y</strong>后继续。</p><p><img src="/posts/windows-phone-upgrade-16212/04.png" alt=""></p><blockquote><p>RCS（Rich Communication Service），在许多Lumia机型中内置。但由于其在之后的更新中已经包含，所以可能会造成冲突以至于无法安装更新。因此，我们需要将它删去。</p><p><em><em>部分非Lumia机型没有内置这个东西(如HP Elite X3)。如果你想知道RCS是否存在，请将手机链接电脑后打开RCS Checker检测</em></em>。</p><p><img src="/posts/windows-phone-upgrade-16212/05.png" alt=""></p></blockquote><p>等待一段时间后，你的手机就升级到1607了</p><blockquote><p>假如你的手机在准备安装更新时报错(如0x800b010a)，可以重试几次甚至直接检查更新——只要确保你在1607时RCS功能被去除。</p></blockquote><hr><h2 id="_2-2-安装interop-tools并解锁" tabindex="-1">2-2 安装Interop Tools并解锁 <a class="header-anchor" href="#_2-2-安装interop-tools并解锁" aria-label="Permalink to “2-2 安装Interop Tools并解锁”">​</a></h2><blockquote><p>此步和2-3、2-4都可以在1511时完成，但我实际测试时出现了各种阴间问题(如应用闪退，解锁后EFISIP分区无法访问等)，所以移到1607来或许会好些。</p></blockquote><blockquote><p><strong>建议</strong> 在这之前重置一次手机，这或许可以降低在16212中出现各种阴间Bug的几率</p></blockquote><p>在<strong>设置-更新与安全-针对开发人员</strong>中打开开发人员模式，顺手把下面<strong>设备发现、设备门户</strong>两个选项也开起来并关闭<strong>设备门户</strong>中的身份验证(后面会有用)</p><p>将手机链接电脑并复制Interop Tools 1.9.400及相应依赖包。将依赖包一个一个安装(中间间隔20秒左右)后再安装主程序。</p><blockquote><p>开启设备门户后，你也可以通过 <a href="http://192.168.101.xxx/" target="_blank" rel="noreferrer">http://192.168.101.xxx/</a> （设置里边有，且需要手机和电脑链接同一个网络）中的App Manager来部署应用，这会方便很多。</p><p><img src="/posts/windows-phone-upgrade-16212/06.png" alt=""></p></blockquote><p>将首次进入的两个选项关闭后进入（如果有）。进入后，点击<strong>This Device</strong>。</p><p>打开菜单，下拉到Interop Unlock并进入。</p><p><img src="/posts/windows-phone-upgrade-16212/07.png" alt=""></p><p>找到并开启<code>Interop/Cap Unlock</code>和<code>Full Filesystem Access</code>这两个选项，将手机重新链接电脑。</p><blockquote><p>如果开启之后这两个选项会自动关闭，你可以尝试先开启<code>Restore NDTKSvc</code>，重启后再试一次</p></blockquote><p><img src="/posts/windows-phone-upgrade-16212/08.png" alt=""></p><hr><h2 id="_2-3-安装开发者菜单" tabindex="-1">2-3 安装开发者菜单 <a class="header-anchor" href="#_2-3-安装开发者菜单" aria-label="Permalink to “2-3 安装开发者菜单”">​</a></h2><p>这时，你可以发现手机链接到电脑后手机目录内多出了许多分区。导航到<code>手机目录\\EFIESP\\Windows\\System32\\Boot</code>，将<code>Develop Menu Installer/Files</code></p><p>中的<code>developermenu.efi</code>重命名为<code>resetphone.efi</code>，然后替换掉手机中原有的<code>resetphone.efi</code>。</p><p><img src="/posts/windows-phone-upgrade-16212/09.png" alt=""></p><p>完成后，重启手机，在开机时同时按住<strong>电源</strong>和<strong>音量-</strong>按钮，若上一步正常完成你就可以进入Developer Menu。</p><hr><h2 id="_2-4-安装测试签名" tabindex="-1">2-4 安装测试签名 <a class="header-anchor" href="#_2-4-安装测试签名" aria-label="Permalink to “2-4 安装测试签名”">​</a></h2><blockquote><p>若没有完成此步，你可能会在准备安装更新的过程中收到<code>0x800b010a</code>的签名验证问题。</p></blockquote><p>选择Mass Storage Mode并进入，链接电脑后<strong>用管理员身份</strong>打开Sample Filght Enabler内的cmd脚本，输入MainOS内的盘符(可以在电脑的文件资源管理器内查看，一般为G)并回车，安装成功后，再次按住<strong>电源</strong>和<strong>音量-</strong>按钮以推出大容量模式并重启。</p><p><img src="/posts/windows-phone-upgrade-16212/10.png" alt=""></p><h2 id="_3-1-推送16212-1000" tabindex="-1">3-1 推送16212.1000 <a class="header-anchor" href="#_3-1-推送16212-1000" aria-label="Permalink to “3-1 推送16212.1000”">​</a></h2><blockquote><p>如果你在推送之前收到了<strong>14393.2551</strong>的更新，可以放心安装。这不会对推送16212造成明显影响。</p></blockquote><p>在正式开始推送之前，请检查下面几项：</p><ul><li>RCS功能未安装(用RCS Cheker检查！)</li><li>打开开发者模式并启用设备门户</li><li>已安装测试签名</li></ul><p>确认无误后，你就可以给手机推送16212了！</p><p>将手机语言调成英文，时间调到<strong>2017年6月2日</strong>，打开Unversal Updater，这次你就可以看到可用更新里边多了个<code>10.0.16212.1000</code>，输入3并回车。</p><p><img src="/posts/windows-phone-upgrade-16212/11.png" alt=""></p><p>这时，程序会询问你是否添加CSheel功能，这取决于你的选择。</p><p><img src="/posts/windows-phone-upgrade-16212/12.png" alt=""></p><blockquote><p>选择&quot;是&quot;，你就可以体验由XAML完全重写的开始菜单。若想要体验16212的新功能，建议选择这个。</p><p>若选择&quot;否&quot;，你将会获得一个和原来基本相同的开始菜单。</p></blockquote><p>选择后，再次等待下载和安装。如果不出意外的话，一个小时之后你就能看到这个界面:</p><p>等到所有应用安装完成后，你就可以愉快地体验16212了。</p><h2 id="_3-2-体验" tabindex="-1">3-2 体验 <a class="header-anchor" href="#_3-2-体验" aria-label="Permalink to “3-2 体验”">​</a></h2><p>更新到16212之后，你可能会发现:</p><ul><li>以前安装的xap应用全部嗝屁——你也无法重新安装</li><li>Edge废了</li><li>实体按键废了</li><li>通知中心无法下拉打开，你需要点击通知栏来打开</li><li>无法从设置更改开发人员模式</li><li>设置里边换不了壁纸</li><li>无法在关机状态下充电</li><li>开机时可能会黑屏一段时间（可以使用WPI或前面提到的设备门户查看设备状态）</li></ul><h2 id="更新过程中可能遇到的错误" tabindex="-1">更新过程中可能遇到的错误 <a class="header-anchor" href="#更新过程中可能遇到的错误" aria-label="Permalink to “更新过程中可能遇到的错误”">​</a></h2><h3 id="iutool-准备更新的过程中出现的问题-可以在手机更新-universal-updater中看到错误码" tabindex="-1">iutool（准备更新的过程中出现的问题，可以在手机更新/Universal Updater中看到错误码） <a class="header-anchor" href="#iutool-准备更新的过程中出现的问题-可以在手机更新-universal-updater中看到错误码" aria-label="Permalink to “iutool（准备更新的过程中出现的问题，可以在手机更新/Universal Updater中看到错误码）”">​</a></h3><ul><li><strong>0x800b010a</strong> 签名验证问题：重做步骤2-4</li><li><strong>0x800b0101</strong> 日期和时间不正确：更改到正确的时间</li><li><strong>0x80188306</strong> 检测到文件冲突或找不到文件：更新到 14393 时包括 RCS cab 和/确保 cab 列表完整且与 InstalledPackages.csv匹配（这个问题我时重刷解决的）</li><li>其他代码可参考 <a href="https://docs.microsoft.com/en-us/previous-versions//mt131833(v=vs.85)?redirectedfrom=MSDN%EF%BC%88%E9%83%A8%E5%88%86%E9%97%AE%E9%A2%98%E6%97%A0%E9%9C%80%E9%87%8D%E5%A4%B4%E6%9D%A5%E8%BF%87%EF%BC%8C%E4%BD%BF%E7%94%A8Universal" target="_blank" rel="noreferrer">https://docs.microsoft.com/en-us/previous-versions//mt131833(v=vs.85)?redirectedfrom=MSDN（部分问题无需重头来过，使用Universal</a> Updater重新推送即可）</li></ul><h3 id="其他问题" tabindex="-1">其他问题 <a class="header-anchor" href="#其他问题" aria-label="Permalink to “其他问题”">​</a></h3><ul><li><strong>无限重启</strong>：重刷</li><li><strong>进入Developer Menu时出现感叹号</strong>：重做步骤2-3</li></ul><h2 id="注意事项-更新到16212之后" tabindex="-1">注意事项（更新到16212之后） <a class="header-anchor" href="#注意事项-更新到16212之后" aria-label="Permalink to “注意事项（更新到16212之后）”">​</a></h2><ul><li>尽早安装Interop Tools和Developer Menu</li><li>最好不要重置手机（虽然这会修复你的Edge，但开发者模式和操作中心也会没掉）</li><li>请勿尝试在16212解锁BL（蓝屏警告）</li><li><strong>不要去动开发者模式！！尤其是在你没有安装Interop Tools和Developer Menu之前！！</strong>（动一下你就改不回来了）</li><li>如果想滚回先前的版本，使用WPI还原</li></ul>',80)])])}const u=o(p,[["render",l]]);export{g as __pageData,u as default};
